// Route LINE events to appropriate handlers
const body = $input.first().json;
const events = body.events || [];

if (events.length === 0) {
  return [{ json: { skip: true } }];
}

const event = events[0];
const eventType = event.type;
const lineUserId = event.source?.userId || '';

let action = 'unknown';
let payload = {};

if (eventType === 'postback') {
  const data = event.postback?.data || '';
  if (data.startsWith('action=')) action = data.replace('action=', '');
  else if (data.startsWith('package=')) {
    action = 'package_selected';
    payload.packageKey = data.replace('package=', '');
  }
} else if (eventType === 'message' && event.message?.type === 'text') {
  action = 'text_message';
  payload.text = event.message.text;
  payload.messageId = event.message.id;
} else if (eventType === 'follow') {
  action = 'new_follower';
}

const packages = {
  basic: { name: 'Basic Relax', price: 499, duration: 45 },
  premium: { name: 'Premium', price: 899, duration: 90 },
  couple: { name: 'Couple Spa', price: 1499, duration: 90 },
  monthly: { name: 'Monthly Pass', price: 2499, duration: null }
};

const packageInfo = payload.packageKey ? packages[payload.packageKey] : null;

return [{
  json: {
    action,
    lineUserId,
    replyToken: event.replyToken || '',
    payload,
    packageInfo,
    rawEvent: event
  }
}];

// Process booking request and prepare for staff approval
const d = $input.first().json.body || $input.first().json;

const packages = {
  basic: { name: 'Basic Relax', price: 499, duration: 45 },
  premium: { name: 'Premium', price: 899, duration: 90 },
  couple: { name: 'Couple Spa', price: 1499, duration: 90 },
  monthly: { name: 'Monthly Pass', price: 2499, duration: null }
};

const pkg = packages[d.packageKey] || packages.basic;
const now = new Date();
const bookingId = `SPA-${now.toISOString().slice(0,10).replace(/-/g,'')}-${Math.floor(1000 + Math.random() * 9000)}`;

return [{
  json: {
    bookingId,
    lineUserId: d.lineUserId,
    customerName: d.customerName || 'ลูกค้า',
    packageKey: d.packageKey,
    packageName: pkg.name,
    packagePrice: pkg.price,
    packageDuration: pkg.duration,
    requestedDate: d.requestedDate,
    requestedTime: d.requestedTime,
    createdAt: now.toISOString(),
    approvalStatus: 'Pending'
  }
}];

