// Generate unique coupon code
function generateCoupon() {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ';
  const nums = '0123456789';
  let code = 'SAUNA-';
  for (let i = 0; i < 3; i++) code += chars[Math.floor(Math.random() * chars.length)];
  for (let i = 0; i < 3; i++) code += nums[Math.floor(Math.random() * nums.length)];
  return code;
}

const d = $input.first().json.body || $input.first().json;
const couponCode = generateCoupon();
const now = new Date();
const expiryDate = new Date(d.bookingDate || now);
expiryDate.setDate(expiryDate.getDate() + 1);

return [{
  json: {
    ...d,
    couponCode,
    approvalTime: now.toISOString(),
    expiryDate: expiryDate.toISOString().slice(0, 10)
  }
}];

// Find bookings where reminder should be sent (24h before booking)
const now = new Date();
const in24h = new Date(now.getTime() + 24 * 60 * 60 * 1000);
const in25h = new Date(now.getTime() + 25 * 60 * 60 * 1000);

const bookings = $input.all().map(r => r.json);

const reminders = bookings.filter(row => {
  if ((row['Reminder Sent'] || '').toString() === 'Yes') return false;
  if ((row['Staff Approval Status'] || '') !== 'Approved') return false;

  const bookingDateStr = row['Booking Date'];
  const bookingTimeStr = row['Booking Time'] || '10:00';
  if (!bookingDateStr) return false;

  const bookingDateTime = new Date(`${bookingDateStr}T${bookingTimeStr}:00`);
  return bookingDateTime >= in24h && bookingDateTime <= in25h;
});

return reminders.map(r => ({ json: r }));
